import unicodedata

ABREVIATIONS = {
    'bsd': 'bordereau de suivi des dechets',
    'dsd': 'declaration des dechets speciaux dangereux',
    'cet': 'centre d enfouissement technique',
    'ma': 'dechets menagers et assimiles',
    'sd': 'dechets speciaux dangereux',
    'loi 01-19': 'loi n 01-19',
    'decret 06-104': 'decret executif n 06-104',
    'decret 05-315': 'decret executif n 05-315',
}


def _normaliser(text):
    """Supprime les accents et met en minuscule."""
    nfkd = unicodedata.normalize('NFKD', text.lower())
    return ''.join(c for c in nfkd if not unicodedata.combining(c))


def rechercher_glossaire(message):
    """Recherche dans le glossaire et retourne les résultats correspondants, triés par pertinence."""
    msg_norm = _normaliser(message)
    mots = [m for m in msg_norm.split() if len(m) >= 2]

    expansion = msg_norm
    expansion_words = []
    expansion_full = ''
    for abbr, full in ABREVIATIONS.items():
        if msg_norm == abbr or (len(abbr) >= 3 and abbr in msg_norm.split()):
            expansion += ' ' + full
            expansion_words = [w for w in full.split() if len(w) >= 3]
            expansion_full = _normaliser(full)

    resultats = []
    for terme in GLOSSAIRE:
        terme_norm = _normaliser(terme['terme_fr'])
        definition_norm = _normaliser(terme['definition_fr'])
        reference_norm = _normaliser(terme.get('reference', ''))
        score = 0

        if msg_norm == terme_norm:
            score = 10
        elif msg_norm in terme_norm or terme_norm.startswith(msg_norm):
            score = 8
        elif expansion_full and expansion_full in terme_norm:
            score = 9
        elif expansion_words and all(w in terme_norm for w in expansion_words):
            score = 8
        elif expansion_words and any(w in terme_norm for w in expansion_words):
            score = 6
        elif expansion_words and any(w in definition_norm for w in expansion_words):
            score = 3
        elif any(mot in terme_norm for mot in mots):
            score = 5
        elif any(mot in definition_norm for mot in mots):
            score = 2
        elif any(mot in reference_norm for mot in mots):
            score = 1

        if score > 0:
            resultats.append((score, terme))

    resultats.sort(key=lambda x: x[0], reverse=True)
    return [t for _, t in resultats[:5]]


def formater_glossaire(resultats):
    """Formate les résultats du glossaire en markdown."""
    if not resultats:
        return ''
    reponse = "## Glossaire des Déchets\n\n"
    for t in resultats:
        classe = f" — Classe {t['classe']}" if t.get('classe') else ''
        reponse += f"**{t['terme_fr']}**{classe}\n\n"
        reponse += f"{t['definition_fr']}\n\n"
        reponse += f"*Réf: {t['reference']}*\n\n"
        reponse += "---\n\n"
    reponse += "_Source : Glossaire conforme à la Loi n°01-19 et au Décret exécutif n°06-104_"
    return reponse
